import axios from 'axios';

const API_URL =
'http://localhost:8080/api/resume';

const AUTH_URL =
'http://localhost:8080/api/auth';

const getToken = () => {

  return localStorage.getItem('token');
};

const axiosInstance = axios.create({

  headers: {

    Authorization:
      `Bearer ${getToken()}`
  }
});

class ResumeService {

  // ====================
  // AUTH
  // ====================

  register(user) {

    return axios.post(

      `${AUTH_URL}/register`,

      user
    );
  }

  login(user) {

    return axios.post(

      `${AUTH_URL}/login`,

      user
    );
  }

  // ====================
  // RESUME CRUD
  // ====================

  getAllResumes() {

    return axiosInstance.get(API_URL);
  }

  saveResume(resume) {

    return axiosInstance.post(
      API_URL,
      resume
    );
  }

  getResumeById(id) {

    return axiosInstance.get(
      API_URL + '/' + id
    );
  }

  updateResume(id, resume) {

    return axiosInstance.put(
      API_URL + '/' + id,
      resume
    );
  }

  deleteResume(id) {

    return axiosInstance.delete(
      API_URL + '/' + id
    );
  }

  // ====================
  // AI SUMMARY
  // ====================

  generateSummary(skills) {

    return axiosInstance.post(

      API_URL + '/generate-summary',

      skills,

      {

        headers: {

          'Content-Type':
          'text/plain'
        }
      }
    );
  }
}

export default new ResumeService();
